# {'a': 1, 'b': 5, 'c': 4}

solution:
def merge_dicts(d1, d2):
    result = d1.copy()
    for k, v in d2.items():
        result[k] = result.get(k, 0) + v
    return result

test_assertions:
assert merge_dicts({'a':1,'b':2},{'b':3,'c':4}) == {'a':1,'b':5,'c':4}
assert merge_dicts({}, {'x':5}) == {'x':5}
print('All tests passed!')

